const allResults = $input.all();
const sources = [
  'TikTok Tendances 2026',
  'Problèmes Entrepreneurs Solo',
  'Agence Web TikTok Idées'
];

const tendances = allResults.map((item, index) => {
  const data = item.json;
  const source = sources[index] || 'Source ' + (index + 1);
  const resultats = [];

  if (data.answer_box) {
    resultats.push({
      titre: data.answer_box.title || 'Encart vedette',
      extrait: data.answer_box.snippet || data.answer_box.answer || ''
    });
  }

  if (data.organic_results && Array.isArray(data.organic_results)) {
    data.organic_results.slice(0, 4).forEach(r => {
      resultats.push({
        titre: r.title || '',
        extrait: r.snippet || ''
      });
    });
  }

  if (data.related_questions && Array.isArray(data.related_questions)) {
    data.related_questions.slice(0, 2).forEach(q => {
      resultats.push({
        titre: q.question || '',
        extrait: q.snippet || ''
      });
    });
  }

  return { source, resultats };
});

return [{ json: { tendances: JSON.stringify(tendances, null, 2) } }];

const raw = $input.first().json.content[0].text;
let scripts;
try {
  scripts = JSON.parse(raw);
} catch (e) {
  // Claude peut ajouter du markdown malgré les instructions
  const cleaned = raw
    .replace(/^```json\s*/m, '')
    .replace(/^```\s*/m, '')
    .replace(/```\s*$/m, '')
    .trim();
  scripts = JSON.parse(cleaned);
}

if (!Array.isArray(scripts)) {
  throw new Error('Claude n a pas retourné un tableau JSON. Réponse : ' + raw.substring(0, 200));
}

return scripts.map(s => ({ json: s }));

const scripts = $input.all();
const date = DateTime.now().setLocale('fr').toFormat('EEEE d MMMM yyyy');

const angleEmoji = { education: '📚', coulisses: '🎭', opinion: '💬' };
const formatEmoji = { texte_anime: '✨', screen_recording: '🖥️', voix_off: '🎙️' };

let rows = '';
scripts.forEach((item, i) => {
  const s = item.json;
  const ae = angleEmoji[s.angle] || '📌';
  const fe = formatEmoji[s.format] || '🎬';
  const tags = Array.isArray(s.hashtags)
    ? s.hashtags.map(h => '<span style="background:#0a2040;color:#1a82d4;padding:2px 7px;border-radius:3px;font-size:11px;">' + h + '</span>').join(' ')
    : String(s.hashtags || '');

  rows += '<tr>';
  rows += '<td style="padding:16px 20px;border-bottom:1px solid #1a3a5c;">';
  rows += '<p style="margin:0 0 6px;color:#1a82d4;font-size:17px;font-weight:bold;">#' + (i + 1) + ' ' + s.hook + '</p>';
  rows += '<p style="margin:0 0 10px;color:#888;font-size:13px;">' + ae + ' ' + s.angle + ' &nbsp;|&nbsp; ' + fe + ' ' + s.format + ' &nbsp;|&nbsp; ⏱ ' + s.duree_secondes + 's</p>';
  rows += '<p style="margin:0 0 10px;color:#ccc;font-size:13px;background:#061020;padding:10px 14px;border-left:3px solid #1a82d4;border-radius:0 4px 4px 0;font-style:italic;">"' + s.cta + '"</p>';
  rows += '<p style="margin:0;">' + tags + '</p>';
  rows += '</td>';
  rows += '</tr>';
});

const html = '<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>'
  + '<body style="margin:0;padding:20px;background:#0d1b2a;font-family:Arial,sans-serif;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" style="max-width:620px;margin:0 auto;">'
  + '<tr><td style="background:#0d1b2a;border:1px solid #1a82d4;border-radius:8px;overflow:hidden;">'
  + '<table width="100%" cellpadding="0" cellspacing="0">'
  + '<tr><td style="padding:22px 20px;background:#061020;border-bottom:2px solid #1a82d4;">'
  + '<h1 style="margin:0;color:#1a82d4;font-size:20px;">🎬 3 scripts TikTok générés</h1>'
  + '<p style="margin:4px 0 0;color:#666;font-size:13px;text-transform:capitalize;">' + date + '</p>'
  + '</td></tr>'
  + rows
  + '<tr><td style="padding:14px 20px;text-align:center;border-top:1px solid #1a3a5c;">'
  + '<p style="margin:0;color:#444;font-size:11px;">DMSW — Système TikTok Automatisé · Les 3 vidéos sont planifiées pour génération</p>'
  + '</td></tr>'
  + '</table></td></tr></table></body></html>';

return [{ json: { html, subject: '🎬 3 scripts TikTok prêts — ' + date, scriptCount: scripts.length } }];
